import { readFileSync, existsSync } from "node:fs";
import assert from "node:assert/strict";

const secrets = JSON.parse(readFileSync("secrets.json", "utf8"));
assert.equal(secrets.alpha, "alpha-orchid-42");
assert.equal(secrets.beta, "beta-cedar-19");
assert.equal(secrets.gamma, "gamma-quartz-88");
assert.equal(secrets.token, "NEBULA-77");
const done = readFileSync("DONE.md", "utf8");
assert.match(done, /alpha-orchid-42/);
assert.match(done, /NEBULA-77/);
const scratch = existsSync(".reaper/memory/scratch.md")
  ? readFileSync(".reaper/memory/scratch.md", "utf8")
  : "";
assert.match(scratch, /NEBULA-77/);
console.log("ok");
